INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028095e3c98b0941765de3', '干净卫生，地理位置很好，出门就是地铁，有商场，去哪里都方便，有很多外国人！服务也挺好，有浴缸，酒店比较有广州特色，据说是白金5星，适合商务出差，一楼有很有名的瀑布餐厅', '["https://dimg04.c-ctrip.com/images/0205o12000al5zma26765_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0230f12000al51msdFB5A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000al47hu009FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000al4mfun4B8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-04', '花园大床房', '大床房', '商务出差', 83, 0, 32, 8, '["交通便利性","周边配套","卫生状况"]'::jsonb, '交通便利性', '周边配套', '卫生状况'),
('68028095e3c98b0941765de4', '酒店装修有特色，前台接待Tony服务态度很好，点赞！', '["https://dimg04.c-ctrip.com/images/0230q12000b7syi4f68BA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000b7s43692F44_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000b7s8ycr47EB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-14', '花园大床房', '大床房', '商务出差', 26, 0, 3, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028095e3c98b0941765de5', '又来花园小住，放开后的花园酒店又恢复了往昔的繁荣，有人气多了，希望新一年越来越好。
小雨中的花园，又是另一翻味道，小桥流水配上毛毛细雨，更像仙境了。酒廊还是一如既往的出色，虽然人多了一点，不过服务还是很好，尤其感谢Yannis和Candy的照顾，下次会再来。', '["https://dimg04.c-ctrip.com/images/0232t12000afpzpr1E3B4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-13', '花园大床房', '大床房', '商务出差', 129, 0, 3, 8, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('680280a1e3c98b0941765de6', '广州入住最满意的酒店了，套房很舒服?? 还有点心赠送。行政酒廊服务不错，早餐很好吃。本来想吃荔枝湾的，但被告知晚上没座位了，可惜。于是去对面广州酒家，结果踩雷了，不建议大家去。。。', '["https://dimg04.c-ctrip.com/images/0203h12000aig32649C92_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0205412000aig30222378_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0201l12000aig353b5461_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0200512000aig5n0cE7F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0200x12000aig32k19EB6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0207312000aig3x5yE04F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-26', '城央绿意双床房', '双床房', '家庭亲子', 90, 0, 23, 7, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('680280a1e3c98b0941765de7', '这次带家人来广州玩几天，主要是逛逛老城区，品品老广美食，最终选择入住花园酒店。
酒店地理位置很好，步行100米就是淘金地铁站，去哪里都非常方便。
酒店虽然开业几十年了，但翻新之后还是很不错，设施齐全，服务非常热情。入住赠送了双人行政礼遇，非常贴心。
这次行程时间紧，酒店的米其林餐厅也没来得及细细品尝，下次来广州我想还是会选择这里。', '["https://dimg04.c-ctrip.com/images/0231y12000agatyrz97CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000agavf3f42FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000agawcb6C6E7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000agavext1914_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000agav7mr0C4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000agav69p7AD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000agavnw1530F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-16', '花园双床房', '双床房', '家庭亲子', 166, 1, 4, 8, '["交通便利性","整体满意度","前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务'),
('680280a1e3c98b0941765de8', '老牌酒店，内部设施很老了，满满的年代感，散发着历史的味道，服务还是不错的，房间卫生可以再改进一些。携程白金卡和岭南汇金卡互通，给升了房，送了行政机遇，虽然吃的很一般，但是可以在花园里喝茶吃蛋糕看孩子两不误也挺好的，很超值。', '["https://dimg04.c-ctrip.com/images/0231z12000af9zow85142_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000af9zwra4311_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000af9zpgl6E77_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000af9zy9z5AF1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000af9zy44EA4B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-01-11', '花园双床房', '双床房', '家庭亲子', 111, 0, 7, 8, '["性价比","整体满意度","卫生状况"]'::jsonb, '性价比', '整体满意度', '卫生状况'),
('680280a1e3c98b0941765de9', '宝藏酒店-广州花园酒店，很久不曾住在广州的内城，楼下的人群摩肩接踵，酒店大堂就像个热闹的集市，绝美的花园，如果喜欢锦鲤几乎可以盯着花园溪水里的锦鲤看上半天时光，包罗世界美味的酒店餐厅，而且一间酒店里最多家米其林餐厅的，可能就是花园酒店里，不同于珠江新城的四季，柏悦，瑰丽，80年代的老酒店，有着独特的味道
特别讲前台接待小胡，知道我们第一次入住特别的介绍了一下酒店，马上就有了好感，特意安排了别具岭南特色的房型，很感谢啦', '["https://dimg04.c-ctrip.com/images/0231412000asv6ruv8AFC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000asv7jnnE787_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000asv0p861F3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000asuyy6v8944_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000asuyi8u3A34_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000asv3xstFC22_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000asv1wbu72D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000asv501140A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000asv5pll9C82_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-23', '花园大床房', '大床房', '情侣出游', 210, 0, 36, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('680280a1e3c98b0941765dea', '非常满意的一次旅行住宿！不愧是广州著名的酒店，服务热情周到。入住当天，前台Wendy 十分贴心地为我们升级了行政商务套房。晚上在锦鲤行政酒廊，体验欢乐时光。酒廊就在内花园，安静优雅。酒廊的Katherine 很暖心地送给我又一份欢乐体验，品尝美点。让人难忘的一次五星级的享受??', '["https://dimg04.c-ctrip.com/images/0235v12000aqytu11E184_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000aqyfhs477CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000aqyoiq31323_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000aqyn35u928C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000aqyk4xyE3C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-07', '花园双床房', '双床房', '家庭亲子', 139, 0, 9, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('680280a1e3c98b0941765deb', '酒店很气派，房间卫生一般，服务还行，早餐品种单一，但是果汁都是nfc果汁，酸奶也不错', '["https://dimg04.c-ctrip.com/images/0233g12000awef0yv4745_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-10', '花园双床房', '双床房', '朋友出游', 42, 0, 5, 5, '["卫生状况","餐饮设施","整体满意度"]'::jsonb, '卫生状况', '餐饮设施', '整体满意度'),
('680280a1e3c98b0941765dec', 'kiki Kristy 服务很好，酒店环境不错，推荐推荐！', '["https://dimg04.c-ctrip.com/images/0230p12000b58nl96C47E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-03', '羊羊得意主题大床房', '主题房', '家庭亲子', 29, 0, 4, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280a1e3c98b0941765ded', '很有气质的一个酒店 满意的体验', '["https://dimg04.c-ctrip.com/images/0235212000bcctb1q6841_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000bcctk2p6A65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000bcctrg24177_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-02', '花园双床房', '双床房', '其他', 15, 0, 3, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('680280a1e3c98b0941765dee', '不愧为中国三大白金级酒店之一，环境优美，有花园和博物馆可以参观，服务热情贴心，早餐丰盛美味，除了床有些软，住感几乎完美。', '["https://dimg04.c-ctrip.com/images/0236712000ar94dz5FF9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000ar8oqmf5573_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000ar8sd3n62B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000ar92kna1500_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-09', '城央绿意双床房', '双床房', '朋友出游', 60, 0, 6, 9, '["整体满意度","餐饮设施","房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施'),
('680280a1e3c98b0941765def', '必须要给酒店一个大大的好评，尤其是前台一位染了头发的个子高高的男生（抱歉忘记了他的姓名）和当时在的主管。
我当时通过携程订的房间，到达前台的时候因为晕机+晕车非常不舒服。结果携程的预订出了问题，当时前台查不到我的订单。这位男生帮我查了很久，看我不舒服先请我在旁边坐下。后来联系携程，好容易订单重新弄好后居然又把我姓名弄错。折腾了好一阵才弄好住宿。
这位男生从头到尾态度非常好，看我带着行李和娃，还有送水。后来还请示主管帮我把房间升级，也送了小礼物。整个过程前台的男生和主管态度都非常好。其实这本来完全不是酒店的问题，但是酒店的态度实在是很令人满意。
于是后来我取消了原本订好的酒店，续住下去。
酒店本身其实有点老，但是交通的确非常方便。周围美食也很多。
后来走的时候又忘记东西在酒店，酒店也专门发了短信来提醒。
服务足以弥补硬件的问题。
酒店的洗漱台非常有特色，在极其有限的空间里营造出了德罗斯特效应。', '["https://dimg04.c-ctrip.com/images/0231n12000anycbff4562_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000anyiean1C95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000anyf59uD31F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-02-13', '花园双床房', '双床房', '家庭亲子', 401, 0, 4, 9, '["前台服务","交通便利性","周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套'),
('680280ace3c98b0941765df0', '作为一家改革开放后的酒店，有近四十年的历史了。服务有程序有规范，设施有做了升级，交通也方便，地铁、巴士都在大门口近旁。', '["https://dimg04.c-ctrip.com/images/0235n12000as8tqfdABB1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000as89nmvF2A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000as885000EF0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000as8bi8w408D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000as88l5j3586_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-03-18', '花园双床房', '双床房', '朋友出游', 59, 0, 4, 7, '["交通便利性","前台服务","房间设施"]'::jsonb, '交通便利性', '前台服务', '房间设施'),
('680280ace3c98b0941765df1', '酒店自带博物馆，每个餐厅都很网红。春节期间人非常多，但是办理入住还比较人性化。
  行政酒廊不错，酒店自带瀑布，可以打卡拍照。后花园有许多锦鲤可以喂养。', '["https://dimg04.c-ctrip.com/images/0233h12000aop2usn0B7F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000aopbkyhDC6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000aop2uso9006_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000aopg0dc1966_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000aopjw2iA648_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000aop9vi4FC18_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000aopcsc1C1ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000aopixgu7513_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000aopbkyiF943_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-18', '花园大床房', '大床房', '家庭亲子', 76, 0, 34, 7, '["公共设施","餐饮设施","前台服务"]'::jsonb, '公共设施', '餐饮设施', '前台服务'),
('680280ace3c98b0941765df2', '体验很好的一次住宿经历，酒店年味很浓，一进大堂就充满浓浓的年味，让我们大年初一从外地来广州度假的人员感觉像过年，服务员态度很好，酒店一楼瀑布餐厅很有特色，景色好，胃口都好了。', '["https://dimg04.c-ctrip.com/images/0236b12000ai11d4k4F35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000ai13ixb5249_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000ai13rh73443_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000ai14mffCEF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000ai13s9eDEB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000ai11q1w62FC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-24', '城央绿意双床房', '双床房', '家庭亲子', 87, 0, 8, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('680280ace3c98b0941765df3', '每次到广州习惯入住这里，服务很周到。', '["https://dimg04.c-ctrip.com/images/0231012000bfv2mx21F2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000bfuv1k1B9D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000bfuxyp5F063_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000bfutwfwC73C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000bfuy2gv8734_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000bfuxae2726E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-18', '花园大床房', '大床房', '商务出差', 18, 0, 1, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('680280ace3c98b0941765df4', '在广州过春节第一站，前台小哥给升级了房间（低价有偿），大堂里春节气氛浓烈，酒店门前有地铁出行方便，最好的地方就是酒店周边步行10分钟内有点都德和陶陶居，咱到广州不就是为了吃嘛！', '["https://dimg04.c-ctrip.com/images/0232612000amj0ceeCE94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000amj1zifA4CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000amitrqm2538_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000amim1qmC20F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000amisxpb8B0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-08', '城央绿意双床房', '双床房', '家庭亲子', 88, 0, 5, 8, '["周边配套","交通便利性","前台服务"]'::jsonb, '周边配套', '交通便利性', '前台服务'),
('680280ace3c98b0941765df5', '设施：大厅非常具有老牌五星酒店的霸气感觉。
卫生：中规中矩。
环境：绝对是非假日酒店界的NO1。感觉比一些假日酒店还好。
服务：几个外籍服务员态度还是不错的。
尊享行政礼遇（包含下午茶和欢乐时光）:绝对超值！必须定！必须定！必须定！', '["https://dimg04.c-ctrip.com/images/0204n12000afumv1c7961_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0203m12000afundjrAEA2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0205r12000afuptgi1054_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-14', '花园双床房', '双床房', '家庭亲子', 116, 1, 5, 7, '["整体满意度","性价比","前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务'),
('680280ace3c98b0941765df6', '酒店服务到位 感谢tony老师办理入住速度很快 酒店博物馆和岭南花园是亮点', '["https://dimg04.c-ctrip.com/images/0233112000bfztmyeC7C5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-18', '花园大床房', '大床房', '家庭亲子', 37, 0, 1, 6, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('680280ace3c98b0941765df7', '从小就听说过花园酒店，这次来广州终于住过了。套间里面设计，装饰和家具还都很新，服务员都主动打招呼，酒店春节期间也装饰的新春喜庆。特别喜欢花园酒店，下次还会来入住。', '["https://dimg04.c-ctrip.com/images/0234012000ajd0g3vD8F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000ajd33yvD41E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000ajd3bnr7275_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000ajd03qv297E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000ajcz0mx33A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000ajd0ijaCC4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000ajcz207E2F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000ajcyeizCC5A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000ajd2uq085DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-29', '花园大床房', '大床房', '家庭亲子', 81, 0, 36, 6, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('680280ace3c98b0941765df8', '酒店大堂很奢华超级气派，有红楼梦金箔墙，在瀑布餐厅用自助餐198一位蛮好的??我们的房间套房住着很舒服，出行很便利哦！', '["https://dimg04.c-ctrip.com/images/0204412000armcb5c064D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0206k12000armjc10FD6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0205a12000armchj4D221_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0203n12000armca6c44C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0204s12000armfiif3E9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0201q12000armf42aDBE5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0202m12000armf42b3658_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0202y12000armbigo35E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0205g12000armix0a57DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-12', '红棉大床套房', '套房', '家庭亲子', 59, 0, 76, 7, '["公共设施","餐饮设施","整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度'),
('680280ace3c98b0941765df9', '有休息厅，房间干净整洁，服务员服务专业，办理入住的帅哥，靓妺很耐信，易于沟通，因要续住一天，Betty的处理方法很暖心，非常感谢！以后出差，旅游还会考虑入住！', '["https://dimg04.c-ctrip.com/images/0230o12000cpl4ym1F23D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000cpl3tzr7227_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000cpl3ly8BD76_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-10', '粤韵双床套房', '套房', '其他', 79, 0, 2, 8, '["前台服务","客房服务","卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况'),
('680280b6e3c98b0941765dfa', '酒店本身的历史文化很丰富，是全国3家白金五星级酒店之一，有自己的博物馆，还有4家米其林餐厅，可惜只体验了荔湾亭，所有的工作人员都很热情和亲切，交通很便利，去哪里都方便，不足的自助餐没什么吃的。小插曲是瀑布餐厅2次把我们房间包含的自助餐人数弄错，就有点无语，不知道为啥会这样
服务：', '["https://dimg04.c-ctrip.com/images/0233312000adeezv24398_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000aded3usAE5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000adele517631_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000adeddn8685B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000ade8eu2E1C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000ademv7pB06D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000adeghsv491E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000adeb33fA741_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000adelj7844FF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-03', '粤韵双床套房', '套房', '家庭亲子', 140, 0, 12, 8, '["餐饮设施","前台服务","交通便利性"]'::jsonb, '餐饮设施', '前台服务', '交通便利性'),
('680280b6e3c98b0941765dfb', '酒店大堂很漂亮，Chloe小姐姐的服务也很好', '["https://dimg04.c-ctrip.com/images/0235r12000b7euuw9CD6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000b7euwe00AA4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000b7eu3kf3D32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-12', '城央绿意大床房', '大床房', '情侣出游', 22, 1, 13, 5, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280b6e3c98b0941765dfd', '五星酒店的典范，服务非常周到，入住离店非常便捷，虽然是老饭店，但感觉一点都不差，很满意！', '["https://dimg04.c-ctrip.com/images/0236s12000atp8uze2ECF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-30', '花园双床房', '双床房', '独自旅行', 44, 0, 1, 6, '["整体满意度","前台服务","退房/入住效率"]'::jsonb, '整体满意度', '前台服务', '退房/入住效率'),
('680280b6e3c98b0941765dfe', '广州5星级宾馆首选，无论环境还是卫生用品餐食服务等均为上佳，性价比超过预期，商务家庭旅游俱可', '["https://dimg04.c-ctrip.com/images/0236x12000asx1p4q186A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-23', '红棉大床套房', '套房', '商务出差', 46, 0, 1, 6, '["整体满意度","性价比","卫生状况"]'::jsonb, '整体满意度', '性价比', '卫生状况'),
('680280b6e3c98b0941765dff', '以前在后面的写字楼上班。这次回来玩住这里特别有亲切感', '["https://dimg04.c-ctrip.com/images/0232112000b4qhuiu8208_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000b4qhs9tB06D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000b4qhtfn6A6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000b4qhvui640A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000b4qhzbmF9BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000b4qhuyyC92A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000b4qhy694C50_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000b4qhyel0FB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000b4qhvpr4E19_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-02', '红棉大床套房', '套房', '家庭亲子', 26, 0, 11, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('680280b6e3c98b0941765e00', '环境好，房间也舒适，有个大浴缸，儿子超喜欢，年三十入住的，超有过年气氛，初一还有醒狮表演，性价比高，自助早餐品种丰富，晚餐也不错，但价位有点高，胜在方便。', '["https://dimg04.c-ctrip.com/images/0235512000ama8kf4BD2C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000amabjlzE49C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000amaawfx59DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000amabmoy630C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000amad0t3D866_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000amaahz1F72A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000amaa5u2F607_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000amaurn30A8D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000amadb6j426A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-07', '花园大床房', '大床房', '家庭亲子', 77, 0, 1, 8, '["性价比","餐饮设施","整体满意度"]'::jsonb, '性价比', '餐饮设施', '整体满意度'),
('680280b6e3c98b0941765e01', '不愧为国家首批五星级酒店，接待服务一流！大堂办理入住的 Gillian非常热情，给我们免费升级到套房。设施齐全，卫生整洁，床品舒适，交通方便，小花园环境优美，特别是米其林美食非常好。下次再来广州还住这里。', '["https://dimg04.c-ctrip.com/images/0236412000dwonr182E2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000dwonuvt097E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000dwontl83A3F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000dwonvws4D7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-07', '红棉双床套房', '套房', '其他', 102, 0, 3, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('680280b6e3c98b0941765e02', '经常来广州，入住都是选择花园酒店，大堂大气，布置的也非常精美好看，前台同事办理入住迅速，房间卫生干净，退房接收到大堂经理lavinia的回访，询问入住体验很贴心。', '["https://dimg04.c-ctrip.com/images/0235512000etjvo9t2D15_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-18', '花园双床房', '双床房', '朋友出游', 81, 0, 3, 8, '["前台服务","卫生状况","整体满意度"]'::jsonb, '前台服务', '卫生状况', '整体满意度'),
('680280b6e3c98b0941765e03', '非常满意，Zoey很热情', '["https://dimg04.c-ctrip.com/images/0231h12000bbu9o8b8111_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-31', '花园双床房', '双床房', '商务出差', 12, 0, 2, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280c7e3c98b0941765e04', '整体都很满意，酒店环境服务都很棒，每个服务员都笑意盈盈，时刻打招呼和询问需求，特别是前台Viria，得知我带父母来游玩，怕老人家舍不得特别给免了加床费，每天的欢迎甜点也很棒，正值中秋还特别准备了小??，唯一美中不足的是酒店手持花洒水温很不稳定，t忽冷忽烫，不知是不是单一间房的问题，老人家洗完澡第二天就感冒发烧了，影响了部分行程，除此之外都挺好', '["https://dimg04.c-ctrip.com/images/0233o12000ca2gdu96686_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000ca2pksn413E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000ca2kupm3356_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-29', '红棉双床套房', '套房', '家庭亲子', 172, 0, 12, 9, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('680280c7e3c98b0941765e05', '作为80年代建成的第一批酒店，到现在还能吸引网红去打卡，可谓经久不衰。酒店充满岭南特色，园林精致，标志性景点18米双瀑布飞流直下，洞里惊现观音像，博物馆记录了酒店行业发展史，专业布置不输省博。比很多酒店都宽敞的健身房、25米游泳池，自由商务办公区，都非常不错。荔湾亭供应的早餐十分丰富，就是有的点心蒸的时间不够，还可以改善。
6.1儿童节入住，特别感谢前台小姐姐Suki的细心接待，帮考虑了老人小孩的需求，安排了全家都满意的红棉套房。', '["https://dimg04.c-ctrip.com/images/0236a12000bcg80fi9E6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000bcgejglF6D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000bcg3hc37CF4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000bcg731z4EAD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000bcg3j2c4159_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000bcg3hc53475_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-06-03', '花园双床房', '双床房', '家庭亲子', 217, 0, 5, 9, '["公共设施","餐饮设施","前台服务"]'::jsonb, '公共设施', '餐饮设施', '前台服务'),
('680280c7e3c98b0941765e06', '广州花园酒店不愧为中国唯三的白金五星级酒店，1985年开业的酒店到最近的装修，后花园贝大师30年前的设计，现在都不过时。广州的米其林餐厅炳胜公馆、江，味道不错。', '["https://dimg04.c-ctrip.com/images/0236k12000ahq8kd8B5E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000ahq87as61B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000ahq7iboB5E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000ahqaz6sE33C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000ahq7uw681FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000ahqa92g8014_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-23', '花园大床房', '大床房', '家庭亲子', 80, 0, 34, 7, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('680280c7e3c98b0941765e07', '房间特别小 没有淋浴的地方 只能站在浴缸里淋浴 然后就造成了滑倒受伤 挺可怕的 卫生也不好 抽屉里还有用过的浴帽 浴缸里有没清理干净的头发 再也不会住这家酒店了', '["https://dimg04.c-ctrip.com/images/0234912000ai87udu72AD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000ai888mbD544_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000ai88nk24614_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-01-25', '城央绿意双床房', '双床房', '家庭亲子', 80, 1, 6, 9, '["房间设施","卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL),
('680280c7e3c98b0941765e08', '交通方便，去哪很方便，服务很好，房间设施虽有点陈旧但设计很合理，床超级超级舒服大赞！瀑布餐厅人很多感受不好，但二楼荔湾粤式餐厅推荐，环境菜品都很好～下次还来', '["https://dimg04.c-ctrip.com/images/0233v12000aiziw5z119E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000aizkxrc2191_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000aizid3uD1E5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-28', '红棉大床套房', '套房', '家庭亲子', 78, 0, 20, 8, '["交通便利性","房间设施","整体满意度"]'::jsonb, '交通便利性', '房间设施', '整体满意度'),
('680280c7e3c98b0941765e09', '卫生减一星是杯子没消毒倒水有奇怪甜味
来广州核心区，周边小吃餐厅餐馆众多
楼下还有广式点心和高级西餐日餐厅
服务中规中矩，酒店内花园非常好赞
就是锦鲤进不去，不然就完美了', '["https://dimg04.c-ctrip.com/images/0234t12000afmcb3b82AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000afmcit91299_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000afmc8i37CCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000afmcs4x7CCD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-01-13', '花园大床房', '大床房', '商务出差', 85, 1, 2, 7, '["卫生状况","周边配套","整体满意度"]'::jsonb, '卫生状况', '周边配套', '整体满意度'),
('680280c7e3c98b0941765e0a', '见过最拥挤的31平米房间 小得放不下两个行李箱 浴室就是一个小浴缸围起来 洗淋浴都要跨进浴缸 老人是没办法用的 本来打算住三天 第二天果断退房换酒店', '["https://dimg04.c-ctrip.com/images/0235612000apu4rrq1CC0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-02-26', '花园双床房', '双床房', '家庭亲子', 74, 0, 1, 8, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('680280c7e3c98b0941765e0b', 'rain 服务很好 酒店环境很棒 下次还会再来', '["https://dimg04.c-ctrip.com/images/0231i12000b4uowtc7DC7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-02', '红棉大床套房', '套房', '朋友出游', 23, 0, 1, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('680280c7e3c98b0941765e0c', '64 平的大床房宽敞舒服，基本的服务也在。但花园酒店确实有点老了，前台迎宾接待的小姐姐培训不专业。以价位来说不如后面两天住的四季酒店。楼下的荔湾亭餐厅好评，值得一试！', '["https://dimg04.c-ctrip.com/images/0231j12000agtjqpmFF42_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-01-18', '红棉大床套房', '套房', '家庭亲子', 83, 0, 1, 8, '["房间设施","前台服务","性价比"]'::jsonb, '房间设施', '前台服务', '性价比'),
('680280c7e3c98b0941765e0d', '作为广州老字号的星级酒店，真的很不错，有瀑布，有后花园，有酒店博物馆，退房的时候人多，又帮我们走快速通道进行办理，总之一切都很好，这次体验很不错', '["https://dimg04.c-ctrip.com/images/0234c12000alsb0tf26D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000als1hpb8082_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000alsn388F4C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000alsfj185826_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-06', '花园大床房', '大床房', '情侣出游', 72, 0, 6, 8, '["公共设施","退房/入住效率","整体满意度"]'::jsonb, '公共设施', '退房/入住效率', '整体满意度'),
('680280d2e3c98b0941765e0e', '行政酒廊的服务人员对我们一家人关爱有加，情人节还赠送了鲜花??环境也是超级棒，适合休闲度假??房间搞卫生的小哥也是非常贴心。', '["https://dimg04.c-ctrip.com/images/0232v12000ap3zea16A65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000ap3k9kmD026_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000ap41c4q9814_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-21', '花园双床房', '双床房', '家庭亲子', 62, 0, 5, 7, '["客房服务","餐饮设施","整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度'),
('680280d2e3c98b0941765e0f', '多次入住花园酒店，服务好，非常喜欢！粤韵房型近年装修，非常满意，下次还会选择花园酒店！
设施：好
卫生：好
环境：好
服务：好', '["https://dimg04.c-ctrip.com/images/0231m12000aoipbs8928C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000aoix6gpB5F3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-16', '花园大床房', '大床房', '商务出差', 63, 0, 4, 5, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('680280d2e3c98b0941765e10', '广州之旅圆满落成，酒店不错 下次可以继续入住', '["https://dimg04.c-ctrip.com/images/0234k12000b4u8y2f72C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000b4u8y2p2862_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000b4u8vqbDFCE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-02', '花园大床房', '大床房', '情侣出游', 22, 0, 12, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('680280d2e3c98b0941765e11', '每次来广州都住花园酒店，服务很好，特别是KIKI，服务无微不至，很热情周到，博物馆很有意思，酒吧驻唱很nice。', '["https://dimg04.c-ctrip.com/images/0231m12000aprnme5D9B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000apryegb6682_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000aprw8dr5603_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000aprw8dsAD7D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000aprr7hn87FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000aprx70yE4CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000aprmdd62FDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000aprta71C882_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-26', '红棉大床套房', '套房', '商务出差', 56, 0, 10, 7, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('680280d2e3c98b0941765e12', '服务非好，酒店环境不错。孩子们玩的很开心', '["https://dimg04.c-ctrip.com/images/0231o12000b564rm9312A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000b5618nlA1FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000b55xa3tB52D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000b563mf237A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000b56ftnqE441_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000b562t30F77E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-03', '花园双床房', '双床房', '朋友出游', 20, 0, 16, 3, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
